mapper.select:
SELECT A.EDU_ID AS EDU_ID, A.EDU_NM AS EDU_NM, SSQ.GET_CODE_NAME('A401', A.CRE_OGN_CCD) AS CRE_OGN_CCD, A.EDU_CCD AS EDU_CCD, A.OGN_NM AS OGN_NM, B.EDU_TGT_CCD AS EDU_TGT_CCD, B.EDU_TGT_CCD_NM AS EDU_TGT_CCD_NM, A.EDU_POS AS EDU_POS, A.DR_DPRT_CD AS DR_DPRT_CD, C.DEP_TITLE AS DEP_TITLE, A.EDU_STS_CD AS EDU_STS_CD, A.EDU_START_DT AS EDU_START_DT, A.EDU_END_DT AS EDU_END_DT, A.EDU_HH AS EDU_HH, A.TCHR_NM AS TCHR_NM, A.TCHR_CERT_CCD AS TCHR_CERT_CCD, A.EDU_CHK_YN AS EDU_CHK_YN, A.EDU_OBJ_CTNT AS EDU_OBJ_CTNT, A.DR_DT AS DR_DT, A.ING_R AS ING_R, (SELECT COUNT(JKW_NO) FROM SSQ.IC_EDU_TGT_JKW D WHERE D.EDU_ID = A.EDU_ID AND D.ING_YN ='Y') AS EDU_CNT, -- 교육 이수자 수 G.LV3, G.GYLJ_ID, G.GYLJ_S_C, (SELECT DTL_C_NM FROM SSQ.SRBA_DTL_C WHERE GRP_C = 'KR04' AND DTL_C = G.GYLJ_S_C) AS GYLJ_S_C_NM, CASE WHEN NVL(G.GYLJ_S_C, 0) = '3' THEN 'Y' /* 지표결재상태코드(A014) = 3(완료) */ ELSE 'N' END FINL_GYLJ_S, /* 최종승인여부 */ NVL(( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM SSQ.C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM SSQ.C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) AS GYLJ_ROLE_ID, ( SELECT CASE WHEN G.GYLJ_S_C = '22' THEN RTN_ROLE_ID ELSE NEXT_GYLJ_ROLE_ID END AS ROLE_ID FROM SSQ.C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA99' AND GYLJ_ROLE_ID = NVL( ( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM SSQ.C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM SSQ.C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) ) as NEXT_GYLJ_ROLE_ID, (SELECT GYLJ_ROLE_ID FROM SSQ.C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA99' AND SNO = (SELECT MIN(SNO) FROM SSQ.C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA99' ) ) AS FIRST_GYLJ, (SELECT GYLJ_ROLE_ID FROM SSQ.C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA99' AND SNO = (SELECT MAX(SNO) FROM SSQ.C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA99' )) AS END_GYLJ FROM SSQ.IC_EDU_M A INNER JOIN ( SELECT EDU_ID, LISTAGG(SSQ.GET_CODE_NAME('A403', EDU_TGT_CCD), ',') WITHIN GROUP (ORDER BY EDU_ID) AS EDU_TGT_CCD_NM, LISTAGG(EDU_TGT_CCD, ',') WITHIN GROUP (ORDER BY EDU_ID) AS EDU_TGT_CCD FROM SSQ.IC_EDU_TGT_CCD GROUP BY EDU_ID ) B ON A.EDU_ID = B.EDU_ID INNER JOIN SSQ.C_DEP_INFO C ON A.DR_DPRT_CD = C.DEP_DESC LEFT JOIN SSQ.SRBA_APPR_M G ON SUBSTR(A.EDU_START_DT,3,8) = G.BAS_YYMM AND A.EDU_ID = G.LV3 WHERE 1=1
AND A.CRE_OGN_CCD = #{CRE_OGN_CCD}
AND (B.EDU_TGT_CCD LIKE '%' || '1001' || '%' AND B.EDU_TGT_CCD LIKE '%' || '1002' || '%')
AND (B.EDU_TGT_CCD NOT LIKE '%' || '1001' || '%' AND B.EDU_TGT_CCD NOT LIKE '%' || '1002' || '%')
AND B.EDU_TGT_CCD LIKE '%' || #{EDU_TGT_CCD} || '%'
AND UPPER(EDU_NM) LIKE '%'|| UPPER(#{EDU_NM}) || '%'
AND A.EDU_CCD = #{EDU_CCD}
AND A.EDU_CHK_YN = #{EDU_CHK_YN}
AND G.GYLJ_S_C = #{GYLJ_S_C}
AND A.EDU_START_DT BETWEEN #{EDU_START_DT} AND #{EDU_END_DT} ORDER BY TO_NUMBER(A.EDU_ID) DESC

