mapper.update:
UPDATE SSQ.IC_EDU_M SET EDU_NM = #{EDU_NM , jdbcType=VARCHAR}, DR_DPRT_CD =#{DR_DPRT_CD , jdbcType=VARCHAR}, CRE_OGN_CCD = #{CRE_OGN_CCD, jdbcType=VARCHAR}, EDU_CCD = #{EDU_CCD, jdbcType=VARCHAR}, EDU_START_DT= #{EDU_START_DT, jdbcType=VARCHAR}, EDU_END_DT = #{EDU_END_DT, jdbcType=VARCHAR}, EDU_POS = #{EDU_POS, jdbcType=VARCHAR}, EDU_HH = #{EDU_HH, jdbcType=VARCHAR}, TCHR_NM = #{TCHR_NM, jdbcType=VARCHAR}, TCHR_HIST = #{TCHR_HIST, jdbcType=VARCHAR}, EDU_OBJ_CTNT = #{EDU_OBJ_CTNT, jdbcType=VARCHAR}, EDU_STD_CNT = #{EDU_STD_CNT, jdbcType=VARCHAR}, EDU_ESTD_CNT = #{EDU_ESTD_CNT, jdbcType=VARCHAR}, EDU_CHK_YN = #{EDU_CHK_YN, jdbcType=VARCHAR}, ATTCH_FILE_NO = #{ATTCH_FILE_NO, jdbcType=VARCHAR},
TCHR_CERT_CCD = #{TCHR_CERT_CCD, jdbcType=VARCHAR},
CHG_DT = to_char(sysdate, 'YYYYMMDD'), CHG_TIME = to_char(sysdate, 'hh24miss'), CHG_OP_JKW_NO = #{CHG_OP_JKW_NO, jdbcType=VARCHAR} WHERE EDU_ID = #{EDU_ID}

mapper.select:
SELECT A.EDU_ID , A.JKW_NO , A.NOTE_CTNT AS USER_NM , NVL(B.DEP_ID , A.DPRT_ID_NUM) AS DEP_ID , COALESCE(B.DEP_TITLE, SUBSTR(TRIM(A.DPRT_CD) ,1,10)) AS DEP_NM , A.JKW_NO , A.EDU_TGT_CCD AS POSITION_NM , A.ING_DT , A.ING_YN FROM (
SELECT A.*, CASE WHEN REGEXP_LIKE(TRIM(A.DPRT_CD) , '^\d+$') THEN TO_NUMBER(TRIM(A.DPRT_CD)) END AS DPRT_ID_NUM FROM SSQ.IC_EDU_TGT_JKW A WHERE A.EDU_ID = #{EDU_ID, jdbcType=VARCHAR}
)A LEFT JOIN SSQ.C_DEP_INFO B ON A.DPRT_ID_NUM = B.DEP_ID ORDER BY NVL(B.DEP_ID , A.DPRT_ID_NUM)

mapper.delete:
DELETE FROM IC_EDU_TGT_JKW                
	WHERE EDU_ID = #{EDU_ID, jdbcType=VARCHAR}
	  AND DPRT_CD = (SELECT DEP_DESC FROM C_DEP_INFO WHERE DEP_TITLE = #{DPRT_NM, jdbcType=VARCHAR})
	  AND JKW_NO = #{JKW_NO, jdbcType=VARCHAR}

